function capitalizeTitle(title) {
  const smallWords = new Set([
    "a","o","as","os",
    "de","da","do","das","dos",
    "e","em","para","por","com",
    "no","na","nos","nas",
    "the","of","and","in","on","at","to","for"
  ]);

  return title
    .toLowerCase()
    .split(/\s+/)
    .map((word, index, arr) => {
      if (
        index !== 0 &&
        index !== arr.length - 1 &&
        smallWords.has(word)
      ) return word;

      return word
        .split("-")
        .map(w => w.charAt(0).toUpperCase() + w.slice(1))
        .join("-");
    })
    .join(" ");
}

